#include<bits/stdc++.h>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define drep(a,b,c) for(int c=(a);c>=(b);--c)
#define Getl() (rand()%(mid-1)+2)
#define Getr() (rand()%(n-mid)+mid+1)
using namespace std;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
const int N=1e4+10;int d[N],a[N],n;
inline bool cmp(const int &x,const int &y){return x>y;}
inline int Cnt(){int s0=0,s1=0,a=0;rep(1,n,i)a+=d[i],s0+=a*a,s1+=a;return s0*n-s1*s1;}
inline void Swap(int &x,int &y){int tmp=x;x=y;y=tmp;}
int main()
{
	srand(time(0));
	n=read();int lst=0,mid=(2+n)>>1,ans=0x3f3f3f3f;
	rep(1,n,i){int x=read();d[i]=x-lst;lst=x;}
	int ll=0,rr=0;while(true)
	{
		sort(d+2,d+mid+1,cmp);sort(d+mid+1,d+n+1);ans=min(ans,Cnt());
		int l=Getl(),r=Getr();while(l==ll&&r==rr)l=Getl(),r=Getr();Swap(d[l],d[r]);
		if((double)clock()/CLOCKS_PER_SEC>0.95){printf("%d\n",ans);return 0;}
	}
}
